#!/usr/bin/env python3
from pathlib import Path
from collections import OrderedDict
ROOT=Path(__file__).resolve().parents[1]
LANGS=['it','fr','de','no','cs']

def read(path):
 d=OrderedDict()
 for raw in path.read_text(encoding='utf-8', errors='replace').splitlines():
  line=raw.strip()
  if not line or line.startswith('#') or '=' not in line: continue
  k,v=line.split('=',1); d[k]=v.replace('\\n','\n')
 return d

def write(path,lang,d):
 with path.open('w',encoding='utf-8',newline='\n') as f:
  f.write(f'# MadModem UI dictionary {lang}\n# Generated by tools/update_ui_translations.py plus v3.11 localization sweep.\n')
  for k,v in d.items(): f.write(f'{k}={v.replace(chr(10),"\\\\n")}\n')
# value maps for remaining visible strings
